import requests

def test_post_api_auth_login_returns_tokens_in_standard_envelope():
    base_url = "http://localhost:8080"
    login_url = f"{base_url}/api/auth/login"
    headers = {
        "Content-Type": "application/json"
    }
    # Seed admin credentials - these must be set according to test environment config
    # Adjust email and password as per seed data in your test environment
    payload = {
        "email": "admin@seed.local",
        "password": "adminpassword"
    }

    try:
        response = requests.post(login_url, json=payload, headers=headers, timeout=30)
    except requests.RequestException as e:
        assert False, f"Request to {login_url} failed: {e}"

    assert response.status_code == 200, f"Expected status 200 but got {response.status_code}"
    try:
        response_json = response.json()
    except ValueError:
        assert False, "Response JSON decoding failed"

    # Assert tokens exist at root level with keys 'access' and 'refresh'
    assert "access" in response_json, "'access' missing in response"
    assert "refresh" in response_json, "'refresh' missing in response"

    # Tokens should be non-empty strings
    assert isinstance(response_json["access"], str) and response_json["access"], "access token is not a non-empty string"
    assert isinstance(response_json["refresh"], str) and response_json["refresh"], "refresh token is not a non-empty string"

test_post_api_auth_login_returns_tokens_in_standard_envelope()
